import React, { useEffect, useState } from "react";
import { db, auth } from "../firebaseConfig";
import { useParams } from "react-router-dom";
import { doc, getDoc, collection, addDoc, getDocs, serverTimestamp } from "firebase/firestore";
import { useAuthState } from "react-firebase-hooks/auth";

const ThreadPage = () => {
  const { id } = useParams();
  const [user] = useAuthState(auth);
  const [thread, setThread] = useState(null);
  const [comments, setComments] = useState([]);
  const [newComment, setNewComment] = useState("");

  useEffect(() => {
    const fetchThread = async () => {
      const threadRef = doc(db, "threads", id);
      const threadSnap = await getDoc(threadRef);
      if (threadSnap.exists()) {
        setThread(threadSnap.data());
      }
    };

    const fetchComments = async () => {
      const commentsRef = collection(db, "threads", id, "comments");
      const commentsSnapshot = await getDocs(commentsRef);
      const commentsList = commentsSnapshot.docs.map((doc) => ({
        id: doc.id,
        ...doc.data(),
      }));
      setComments(commentsList);
    };

    fetchThread();
    fetchComments();
  }, [id]);

  const handleCommentSubmit = async (e) => {
    e.preventDefault();
    if (!user) {
      alert("You must be logged in to comment.");
      return;
    }

    try {
      await addDoc(collection(db, "threads", id, "comments"), {
        content: newComment,
        author: user.email,
        createdAt: serverTimestamp(),
      });
      alert("Comment added!");
      setNewComment("");
      window.location.reload(); // Refresh page to show new comment
    } catch (error) {
      console.error("Error adding comment:", error);
    }
  };

  return (
    <div className="container">
      {thread ? (
        <>
          <h1>{thread.title}</h1>
          <p>{thread.content}</p>
          <p><strong>Posted by:</strong> {thread.author}</p>

          <h2>Comments</h2>
          {comments.length === 0 ? <p>No comments yet.</p> : (
            comments.map((comment) => (
              <div key={comment.id}>
                <p><strong>{comment.author}:</strong> {comment.content}</p>
              </div>
            ))
          )}

          {user && (
            <form onSubmit={handleCommentSubmit}>
              <textarea
                placeholder="Write a comment..."
                value={newComment}
                onChange={(e) => setNewComment(e.target.value)}
                required
              ></textarea>
              <button type="submit">Post Comment</button>
            </form>
          )}
        </>
      ) : (
        <p>Loading thread...</p>
      )}
    </div>
  );
};

export default ThreadPage;
