import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { db } from "../firebaseConfig";
import { doc, getDoc, collection, query, where, getDocs } from "firebase/firestore";
import { useAuthState } from "react-firebase-hooks/auth";
import { auth } from "../firebaseConfig";

function Profile() {
  const { userId } = useParams();
  const [user] = useAuthState(auth);
  const [userData, setUserData] = useState(null);
  const [userThreads, setUserThreads] = useState([]);

  useEffect(() => {
    const fetchUserData = async () => {
      try {
        const userRef = doc(db, "users", userId);
        const userSnap = await getDoc(userRef);

        if (userSnap.exists()) {
          setUserData(userSnap.data());
        } else {
          console.error("User not found");
        }
      } catch (error) {
        console.error("Error fetching profile:", error);
      }
    };

    const fetchUserThreads = async () => {
      try {
        const threadsRef = collection(db, "threads");
        const q = query(threadsRef, where("userId", "==", userId));
        const threadDocs = await getDocs(q);
        setUserThreads(threadDocs.docs.map(doc => ({ id: doc.id, ...doc.data() })));
      } catch (error) {
        console.error("Error fetching user threads:", error);
      }
    };

    fetchUserData();
    fetchUserThreads();
  }, [userId]);

  if (!userData) return <h1>Loading Profile...</h1>;

  return (
    <div className="profile-container">
      <h1>{userData.username}'s Profile</h1>
      <img src={userData.avatar || "https://via.placeholder.com/150"} alt="User Avatar" />
      <p><strong>Email:</strong> {userData.email}</p>
      <p><strong>Joined:</strong> {userData.joinedAt?.toDate().toLocaleDateString() || "N/A"}</p>
      {user && user.uid === userId && <button>Edit Profile</button>}
      <h2>Threads by {userData.username}</h2>
      <ul>
        {userThreads.map(thread => (
          <li key={thread.id}>
            <a href={`/thread/${thread.id}`}>{thread.title}</a>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default Profile;
