import React, { useState } from "react";
import { auth, db } from "../firebaseConfig";
import { createUserWithEmailAndPassword, updateProfile } from "firebase/auth";
import { doc, setDoc, serverTimestamp } from "firebase/firestore";
import { useNavigate } from "react-router-dom";
import ReCAPTCHA from "react-google-recaptcha";

const SignUp = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [username, setUsername] = useState("");
  const [captchaVerified, setCaptchaVerified] = useState(false);
  const navigate = useNavigate();

  const handleCaptchaChange = (value) => {
    if (value) {
      setCaptchaVerified(true); // Successfully validated
    } else {
      setCaptchaVerified(false); // Failed validation
    }
  };

  const handleSignUp = async (e) => {
    e.preventDefault();

    if (!captchaVerified) {
      alert("Please verify the CAPTCHA before signing up. 🛑");
      return; // Stop form submission
    }

    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const user = userCredential.user;

      // Update Firebase Auth profile
      await updateProfile(user, { displayName: username });

      // Save user profile in Firestore
      await setDoc(doc(db, "users", user.uid), {
        username,
        email,
        joinedAt: serverTimestamp(),
        avatar: "", // Default avatar placeholder
      });

      alert("Sign Up Successful! 🎉");
      navigate(`/profile/${user.uid}`); // Redirect to profile
    } catch (error) {
      alert(error.message);
    }
  };

  return (
    <div className="container">
      <h2>Sign Up</h2>
      <form onSubmit={handleSignUp}>
        <input
          type="text"
          placeholder="Username"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          required
        />
        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
        />
        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
        />
        
        {/* reCAPTCHA Validation */}
        <ReCAPTCHA
          sitekey="YOUR_RECAPTCHA_SITE_KEY" // Replace with your site key
          onChange={handleCaptchaChange}
        />

        <button type="submit">Sign Up</button>
      </form>
    </div>
  );
};

export default SignUp;
