import React from 'react';
import './style.css';
import {
  BrowserRouter as Router,
  Routes,
  Route,
} from 'react-router-dom';

import Home from './pages/Home.js';
import SignUp from './pages/SignUp.js';
import SignIn from './pages/SignIn.js';
import ThreadPage from './pages/ThreadPage.js';
import CategoryPage from './pages/CategoryPage.js';
import CreateThread from './pages/CreateThread.js';
import Profile from './pages/Profile.js';
import Header from './components/Header.js';
import Footer from './components/Footer.js';
import { auth } from './firebaseConfig';
import { useAuthState } from 'react-firebase-hooks/auth';

function App() {
  const [user, loading] = useAuthState(auth);

  if (loading) return <h1>Loading...</h1>; // Show loading screen while Firebase checks authentication

  return (
    <Router>
      <Header />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/signup" element={<SignUp />} />
        <Route path="/signin" element={<SignIn />} />
        <Route path="/thread/:id" element={<ThreadPage />} />
        <Route path="/category/:name" element={<CategoryPage />} />
        {user && <Route path="/create" element={<CreateThread />} />}
        <Route path="/profile/:userId" element={<Profile />} />
      </Routes>
      <Footer />
    </Router>
  );
}

export default App;
